import os, re, json, csv
from collections import defaultdict

# ===== STEP 1: Parse raw_orders =====
# Files: day_XXX_S_Y_format.ext
# Formats: text-template.txt, key-value.txt, table-csv.csv, api-json.json
orders = {}  # (day, store_id) -> {product_id: qty}

def parse_order_file(filepath, day, store_id):
    content = open(filepath).read()
    if filepath.endswith('_text-template.txt'):
        # "Order from Day_X. Please deliver YY units of product P_Z. Regards, Store S_W."
        prods = {}
        for line in content.strip().split('\n'):
            m = re.search(r'(\d+)\s+units of product\s+(P_\d+)', line)
            if m:
                qty, prod = int(m.group(1)), m.group(2)
                prods[prod] = qty
        return prods
    elif filepath.endswith('_key-value.txt'):
        # "RECEIVER: S_W | ORDER_PRODUCT: P_Z | ORDER_QTY: YY"
        prods = {}
        for line in content.strip().split('\n'):
            m = re.search(r'ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)', line)
            if m:
                prod, qty = m.group(1), int(m.group(2))
                prods[prod] = qty
        return prods
    elif filepath.endswith('_table-csv.csv'):
        # PRODUCT;QUANTITY
        prods = {}
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2:
                prods[parts[0]] = int(parts[1])
        return prods
    elif filepath.endswith('_api-json.json'):
        data = json.loads(content)
        prods = {}
        for item in data['items']:
            prods[item['prod_id']] = item['qty']
        return prods

print("Parsing raw_orders...")
for fname in os.listdir('/app/raw_orders'):
    m = re.match(r'day_(\d+)_S_(\d+)_.+', fname)
    if m:
        day, sid = int(m.group(1)), f"S_{m.group(2)}"
        fpath = os.path.join('/app/raw_orders', fname)
        prods = parse_order_file(fpath, day, sid)
        orders[(day, sid)] = prods

print(f"Parsed {len(orders)} order entries")

# ===== STEP 2: Parse supplier receipts =====
# Files: day_XXX_PR_YY.format
# Formats: table-csv.csv, text-template.txt, key-value.txt, api-json.json
supplier_deliveries = {}  # (day, producer_id) -> {product_id: qty}

def parse_supplier_file(filepath):
    content = open(filepath).read()
    if filepath.endswith('_table-csv.csv'):
        prods = {}
        for line in content.strip().split('\n')[1:]:
            parts = line.strip().split(';')
            if len(parts) >= 2:
                prods[parts[0]] = int(parts[1])
        return prods
    elif filepath.endswith('_text-template.txt'):
        # "Supplier PR_YY delivered ZZ units of product P_X to the wholesaler on Day_W."
        prods = {}
        for line in content.strip().split('\n'):
            m = re.search(r'delivered\s+(\d+)\s+units of product\s+(P_\d+)', line)
            if m:
                qty, prod = int(m.group(1)), m.group(2)
                prods[prod] = qty
        return prods
    elif filepath.endswith('_key-value.txt'):
        # "PRODUCT: P_X | DELIVERED_QTY: ZZ"
        prods = {}
        for line in content.strip().split('\n'):
            m = re.search(r'PRODUCT:\s*(P_\d+)\s*\|\s*DELIVERED_QTY:\s*(\d+)', line)
            if m:
                prod, qty = m.group(1), int(m.group(2))
                prods[prod] = qty
        return prods
    elif filepath.endswith('_api-json.json'):
        data = json.loads(content)
        prods = {}
        for item in data['items']:
            prods[item['prod_id']] = item['delivered_qty']
        return prods

print("Parsing raw_supplier_receipts...")
for fname in os.listdir('/app/raw_supplier_receipts'):
    m = re.match(r'day_(\d+)_PR_(\d+)_.+', fname)
    if m:
        day, prid = int(m.group(1)), f"PR_{m.group(2)}"
        fpath = os.path.join('/app/raw_supplier_receipts', fname)
        prods = parse_supplier_file(fpath)
        supplier_deliveries[(day, prid)] = prods

print(f"Parsed {len(supplier_deliveries)} supplier delivery entries")

# ===== STEP 3: Parse wholesaler receipts =====
# Files: day_XXX_PR_YY_receipt.txt
# DAY: X, SUPPLIER_ID: PR_YY, DAILY_SEQUENCE_NO: Z
wholesaler_sequences = {}  # (day, producer_id) -> sequence_no

print("Parsing raw_wholesaler_receipts...")
for fname in os.listdir('/app/raw_wholesaler_receipts'):
    m = re.match(r'day_(\d+)_PR_(\d+)_receipt\.txt', fname)
    if m:
        day, prid = int(m.group(1)), f"PR_{m.group(2)}"
        content = open(os.path.join('/app/raw_wholesaler_receipts', fname)).read()
        seq_m = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
        if seq_m:
            wholesaler_sequences[(day, prid)] = int(seq_m.group(1))

print(f"Parsed {len(wholesaler_sequences)} wholesaler receipt entries")

# ===== STEP 4: Parse wholesaler store receipts =====
# Files: day_XXX_S_YY_receipt.txt
# DAY: X, STORE_ID: S_YY, DAILY_SEQUENCE_NO: Z, TOTAL_DELIVERED_UNITS: W
store_receipts = {}  # (day, store_id) -> (sequence_no, total_units)

print("Parsing raw_wholesaler_store_receipts...")
for fname in os.listdir('/app/raw_wholesaler_store_receipts'):
    m = re.match(r'day_(\d+)_S_(\d+)_receipt\.txt', fname)
    if m:
        day, sid = int(m.group(1)), f"S_{m.group(2)}"
        content = open(os.path.join('/app/raw_wholesaler_store_receipts', fname)).read()
        seq_m = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content)
