        if seq_m and units_m:
            store_receipts[(day, sid)] = (int(seq_m.group(1)), int(units_m.group(1)))

print(f"Parsed {len(store_receipts)} store receipt entries")

# ===== STEP 5: Parse sales_log =====
sales_data = defaultdict(list)  # (day, store, product) -> list of (reported_demand, sold_qty, lost_sales)

print("Parsing sales_log.csv...")
with open('/app/sales_log.csv') as f:
