            sold_batches[sid][prod][day] = max(bp.items(), key=lambda x: x[1])[0]

# For each producer-product combination, compute the average demand ratio 
# in the 14 days AFTER their batch is sold (at a given store).
# Compare to the 14 days before.

# Collect all events: (store, prod, day, producer)
events = []
for store in sold_batches:
    for prod in sold_batches[store]:
        for day, producer in sold_batches[store][prod].items():
            if day > 350:  # Skip end of year
                continue
            events.append((store, prod, day, producer))

# For each event, compute before/after avg demand
# Then for each producer-prod, compute overall effect
producer_prod_effects = defaultdict(lambda: defaultdict(list))

for store, prod, day, producer in events:
    if (store, prod) not in sp_daily:
        continue

    ddict = sp_daily[(store, prod)]

    # 14 days before (days -21 to -7)
    before = [ddict.get(day - o, {}).get('total', 0) for o in range(7, 22) if day - o in ddict]

    # 14 days after (days +1 to +14)
    after = [ddict.get(day + o, {}).get('total', 0) for o in range(1, 15) if day + o in ddict]

    if len(before) < 5 or len(after) < 5:
        continue

    before_avg = sum(before) / len(before)
    after_avg = sum(after) / len(after)

    if before_avg < 5:
        continue

    effect = (after_avg - before_avg) / before_avg
    producer_prod_effects[prod][producer].append(effect)

# Now compute the average effect per producer-product
avg_effect = {}  # {prod: {producer: avg_effect}}
for prod, producer_data in producer_prod_effects.items():
    avg_effect[prod] = {}
    for producer, effects in producer_data.items():
        if len(effects) >= 3:  # Need multiple observations
            avg_effect[prod][producer] = (sum(effects) / len(effects), len(effects))

# For each product, find producers with consistently negative effects
confirmed = defaultdict(list)
for prod, pe in avg_effect.items():
    if not pe:
        continue

    # Compute product-level average effect across all producers
    all_effects = [v[0] for v in pe.values()]
    prod_avg = sum(all_effects) / len(all_effects)
    prod_std = (sum((e - prod_avg)**2 for e in all_effects) / len(all_effects))**0.5

    # Find producers with very negative effects (below 1.5 std from mean)
    # Also require at least some observations
    for producer, (effect, count) in sorted(pe.items(), key=lambda x: x[1][0]):
        threshold = prod_avg - 0.5 * prod_std  # Minimum threshold
        if effect < threshold and effect < -0.05 and count >= 3:
            confirmed[prod].append((producer, effect, count))

# Sort and print
print("Producers with below-average post-sale demand by product:")
print("(producer, avg_effect, num_events)\n")

for prod in sorted(confirmed.keys()):
    confirmed[prod].sort(key=lambda x: x[1])
    print(f"{prod}:")
    for p, e, c in confirmed[prod]:
        print(f"  {p}: avg_effect={e:.4f}, n={c}")
    print()

# Build answer
all_products = sorted(set(p for (_, p) in sp_daily.keys()))
answer = {}
for prod in all_products:
    if prod in confirmed and confirmed[prod]:
        answer[prod] = sorted([p for p, _, _ in confirmed[prod]])
    else:
        answer[prod] = []

print("===== FINAL ANSWER =====")
print(json.dumps(answer, indent=2))
